package com.company.supervision.api;import com.company.supervision.application.organization.OrganizationQueryService;import com.company.supervision.entity.dto.ApiResult;import org.springframework.web.bind.annotation.*;@RestController @RequestMapping("/organization")public class OrganizationController{private final OrganizationQueryService s;public OrganizationController(OrganizationQueryService s){this.s=s;}@GetMapping("/departments")public ApiResult<?>tree(){return ApiResult.ok(s.tree());}@GetMapping("/departments/{id}")public ApiResult<?>department(@PathVariable Long id){return ApiResult.ok(s.department(id));}@GetMapping("/persons")public ApiResult<?>people(@RequestParam(required=false)Long departmentId,@RequestParam(required=false)String keyword,@RequestParam(required=false)Integer status,@RequestParam(required=false)String gender,@RequestParam(required=false)String syncStatus,@RequestParam(defaultValue="1")int page,@RequestParam(defaultValue="20")int size){return ApiResult.ok(s.people(departmentId,keyword,status,gender,syncStatus,page,size));}@GetMapping("/persons/{id}")public ApiResult<?>person(@PathVariable Long id){return ApiResult.ok(s.person(id));}}
